<svg viewBox="0 0 700 620" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Campagne de plaintes de la CFTC : Kentucky vs. Caroline du Nord</text>
  <g font-family="sans-serif">
    <text x="20" y="58" fill="#a1a1aa" font-size="13">1. Campagne de plaintes de la CFTC (depuis avril 2026)</text>
